def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}
    status = s["status"]

    if name == "propose":
        # Open a new pending edit, but only when none is in flight. The proposed
        # content rides in on the action params (defaults to a placeholder edit).
        if status in ("idle", "applied", "denied"):
            s["pending_edit"] = str(params.get("content", "edit"))
            s["status"] = "proposed"
            s["proposed"] = s["proposed"] + 1

    elif name == "approve":
        # Grant permission. The gate only opens for an edit that was proposed.
        if status == "proposed":
            s["status"] = "approved"
            s["approved"] = s["approved"] + 1

    elif name == "apply":
        # Commit the edit to the document -- gated on a prior approval. Applying
        # an un-approved edit changes nothing: the agent cannot bypass the gate.
        if status == "approved":
            s["applied_content"] = s["pending_edit"]
            s["pending_edit"] = ""
            s["status"] = "applied"
            s["applied"] = s["applied"] + 1

    elif name == "deny":
        # Reject and discard an in-flight edit (whether merely proposed or even
        # already approved). The pending content is dropped, never committed.
        if status in ("proposed", "approved"):
            s["pending_edit"] = ""
            s["status"] = "denied"
            s["denied"] = s["denied"] + 1

    return s

