def perceive(data):
    # Intake an edit request pasted as text, e.g.:
    #     edit: fix the typo in the header
    # Surfaces it as a pending proposal the gate can then approve/apply/deny.
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip().lower(); v = v.strip()
            if k in ('edit', 'content', 'proposal', 'propose'):
                out['pending_edit'] = v
                out['status'] = 'proposed'
    return out
